#include <cstdio>
#include <omp.h>

#define N 1024
#define T 100

void stencil_1d(float *in, float *out, int n, int t) {
    for (int time = 0; time < t; time++) {
#pragma omp parallel for
        for (int i = 1; i < n - 1; i++) {
            out[i] = 0.33333f * (in[i - 1] + in[i] + in[i + 1]);
        }
        // swap pointers
        float* temp = in;
        in = out;
        out = temp;
    }
    // If number of iterations is even, result is in 'in', else in 'out'
    if (t % 2 == 1) {
        for (int i = 0; i < n; i++) {
            out[i] = in[i];
        }
    }
}

int main() {
    float *in = new float[N];
    float *out = new float[N];

    // Initialize input data
    for (int i = 0; i < N; i++) {
        in[i] = i;
        out[i] = 0.0f;
    }

    stencil_1d(in, out, N, T);

    // Print some of the results
    for (int i = 0; i < 10; i++) {
        printf("%f ", out[i]);
    }
    printf("\n");

    delete[] in;
    delete[] out;
    return 0;
}
